public IntentResult detectIntent(String message) {
return new IntentResult(
"GET_PO_STATUS",
Map.of("poNumber", "4500012345")
);
}
public BotResponse handleIntent(IntentResult intent, UserContext user) {
PolicyDecision decision =
policyEngine.evaluate(intent, user);
if (decision.requiresApproval()) {
sagaService.pauseForApproval(decision);
return BotResponse.adaptiveCard(
approvalCardBuilder.build(decision)
);
}
Object result = executor.execute(intent);
return BotResponse.text(result.toString());
}
